from typing import List, Dict, Any, Optional, Callable
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict


def apply_dynamic_filters(
    search_results: List[SearchResult],
    filter_specs: Dict[str, Dict[str, Any]],
    filter_logic: str = "AND"
) -> List[SearchResult]:
    """Apply dynamic metadata filters to search results with configurable logic.

    Args:
        search_results: List of SearchResult objects to filter
        filter_specs: Dictionary of filter specifications.
            Format: {"field_name": {"operator": value}}
            Example: {"category": {"==": "tech"}, "rating": {">=": 4.0}}
        filter_logic: "AND" (all filters must match) or "OR" (any filter matches)

    Returns:
        Filtered list of SearchResult objects
    """
    if not search_results or not filter_specs:
        return search_results

    # Convert SearchResult objects to dictionaries for filtering
    result_dicts = []
    result_mapping = {}

    for idx, result in enumerate(search_results):
        # Convert SearchResult to dictionary format
        result_dict = {
            'id': idx,
            'object': result
        }

        # Extract metadata from SearchResult (assuming it has metadata attributes)
        if hasattr(result, 'metadata') and result.metadata:
            result_dict.update(result.metadata)
        else:
            # If no metadata attribute, try to convert the object itself
            try:
                if hasattr(result, '__dict__'):
                    result_dict.update(result.__dict__)
                elif hasattr(result, '_asdict'):  # For namedtuples
                    result_dict.update(result._asdict())
            except:
                pass

        result_dicts.append(result_dict)
        result_mapping[idx] = result

    # Create filter engine
    engine = MetadataFilterEngine()

    # Add filters based on specifications
    for field_name, operator_dict in filter_specs.items():
        for operator, value in operator_dict.items():
            engine.add_filter(field_name, operator, value)

    # Apply filters with specified logic
    if filter_logic.upper() == "AND":
        filtered_dicts = engine.apply_and_filters(result_dicts)
    elif filter_logic.upper() == "OR":
        filtered_dicts = engine.apply_or_filters(result_dicts)
    else:
        raise ValueError(f"Unsupported filter logic: {filter_logic}. Use 'AND' or 'OR'.")

    # Convert back to SearchResult objects
    filtered_results = []
    for result_dict in filtered_dicts:
        original_idx = result_dict.get('id')
        if original_idx is not None and original_idx in result_mapping:
            filtered_results.append(result_mapping[original_idx])

    return filtered_results

